```c++
#include <iostream>
#include <windows.h>
#include <bluetoothapis.h>

int main()
{
    // Initialize the Bluetooth API
    DWORD dwResult = 0;
    WSADATA wsaData;
    if ((dwResult = WSAStartup(MAKEWORD(2, 2), &wsaData)) != 0)
    {
        std::cerr << "WSAStartup failed: " << dwResult << std::endl;
        return 1;
    }

    // Create a Bluetooth radio
    HANDLE hRadio = nullptr;
    if ((hRadio = ::BluetoothFindFirstRadio(nullptr, &hRadio)) == nullptr)
    {
        std::cerr << "BluetoothFindFirstRadio failed: " << ::GetLastError() << std::endl;
        WSACleanup();
        return 1;
    }

    // Scan for nearby Bluetooth devices
    BLUETOOTH_DEVICE_SEARCH_PARAMS searchParams{};
    searchParams.dwSize = sizeof(searchParams);
    searchParams.fIssueInquiry = TRUE;
    searchParams.cTimeoutMultiplier = 2;
    searchParams.hRadio = hRadio;
    HBLUETOOTH_DEVICE_FIND hFind = nullptr;
    if ((hFind = ::BluetoothFindFirstDevice(&searchParams, &deviceInfo)) == nullptr)
    {
        std::cerr << "BluetoothFindFirstDevice failed: " << ::GetLastError() << std::endl;
        ::BluetoothFindRadioClose(hRadio);
        WSACleanup();
        return 1;
    }

    // Print information about each discovered Bluetooth device
    do
    {
        BLUETOOTH_DEVICE_INFO deviceInfo{};
        deviceInfo.dwSize = sizeof(deviceInfo);
        if (::BluetoothGetDeviceInfo(hFind, &deviceInfo) == ERROR_SUCCESS)
        {
            std::cout << "Name: " << deviceInfo.szName << std::endl;
            std::cout << "Address: " << std::hex << deviceInfo.Address.ullLong << std::endl;
            std::cout << "Class: " << std::hex << deviceInfo.ulClassofDevice << std::endl;
            std::cout << std::endl;
        }
    } while (::BluetoothFindNextDevice(hFind, &deviceInfo));

    ::BluetoothFindDeviceClose(hFind);
    ::BluetoothFindRadioClose(hRadio);
    WSACleanup();

    return 0;
}
```

Note that this code uses the Microsoft Bluetooth APIs on Windows, so it may not work on other platforms or with other Bluetooth hardware. It also only scans for nearby devices and displays basic information about them; more advanced features (like pairing or connecting to a device) would require additional code.

